/* Load persisted data with corruption guard */
function _loadST(){
  try{
    const raw=localStorage.getItem('kpi_v3');
    if(!raw)return{};
    const d=JSON.parse(raw);
    /* Validate basic structure — if corrupted, wipe and start fresh */
    if(typeof d!=='object'||Array.isArray(d))return{};
    /* Remove null overrides that would blank out BASE data */
    if(d.ov){
      Object.keys(d.ov).forEach(kId=>{
        if(!d.ov[kId])return;
        ['q1','q2','q3','q4'].forEach(q=>{
          if(d.ov[kId][q]===null||d.ov[kId][q]===undefined)
            delete d.ov[kId][q];  /* Keep BASE value */
        });
        if(Object.keys(d.ov[kId]).length===0)delete d.ov[kId];
      });
    }
    return d;
  }catch(_){return{};}
}
