/* ==========================================
   UTILS
========================================== */
var f2 =(v,d=1)=>v==null?'\u2014':v.toFixed(d)+'%';
function qv(k){
  /* Guard: skip malformed KPI records */
  if(!k||typeof k!=='object') return null;
  /* Safe filter object — never read F.qtr directly */
  const FF=(typeof F!=='undefined'&&F&&typeof F==='object')
    ?F:{year:'all',qtr:['q1','q2','q3','q4'],dept:'all',status:'all'};
  const _qtr=Array.isArray(FF.qtr)?FF.qtr:['q1','q2','q3','q4'];
  const qs=_qtr.includes('all')?['q1','q2','q3','q4']:_qtr;
  const vs=qs.map(q=>k[q]).filter(v=>v!==null&&v!==undefined&&typeof v==='number');
  return vs.length?vs.reduce((a,b)=>a+b)/vs.length:null;
}
/* Unified met/missed check — respects k.op (>=, <=, =) */
function metStatus(k,v){
  if(v===null||v===undefined)return null;
  if(k.op==='=')return Math.abs(v-k.target)<=0.05;
  if(k.op==='<=')return v<=k.target;
  return v>=k.target;
}
function ok(k){const v=qv(k);return metStatus(k,v);}
function kc(k){const a=ok(k);return a===null?'var(--t3)':a?'var(--green)':'var(--red)';}
/* Binary band: 0=N/A, 1=Missed(red), 2=Met(green) */
function pb(val,k){if(val===null)return 0;return metStatus(k,val)?2:1;}
function getRepeat(k){
  let c=0,max=0;
  [k.q1,k.q2,k.q3,k.q4].forEach(v=>{if(v!==null){if(!metStatus(k,v)){c++;max=Math.max(max,c);}else c=0;}});
  return max;
}
function filt(){
  /* Safe filter object — never access F directly; use FF throughout */
  const FF = (typeof F !== 'undefined' && F && typeof F === 'object')
    ? F
    : { year:'all', qtr:['q1','q2','q3','q4'], dept:'all', status:'all' };

  /* Sync FF.dept with role lock to prevent drift */
  if(window._lockedDept && FF.dept !== window._lockedDept) FF.dept = window._lockedDept;

  return allK().filter(k=>{
    /* Guard: skip any record that is not a plain object */
    if(!k || typeof k !== 'object') return false;

    /* Guard individual fields used below */
    const kId   = k.id   != null ? String(k.id)   : '';
    const kDept = k.dept != null ? String(k.dept)  : '';
    const kYr   = k.yr   != null ? String(k.yr)    : '';
    /* k.owner and k.code are normalised by normalizeKpiRecord so just guard presence */
    const kOwner= k.owner != null ? String(k.owner) : '';
    const kCode = k.code  != null ? String(k.code)  : '';

    /* ── Hard dept lock: dept_manager and kpi_owner never see other depts ── */
    if(window._lockedDept && kDept !== window._lockedDept) return false;

    /* ── KPI Owner: show only assigned KPIs ── */
    if(window._fbRole === 'kpi_owner'){
      const assigned = window._fbAssignedKpis;
      if(Array.isArray(assigned) && assigned.length > 0 && !assigned.includes(kId)) return false;
    }

    /* ── Standard filters using FF (safe) ── */
    if(FF.year && FF.year !== 'all' && kYr !== FF.year) return false;
    if(FF.dept && FF.dept !== 'all' && kDept !== FF.dept) return false;
    if(FF.status && FF.status !== 'all'){
      const a = ok(k);
      if(FF.status === 'achieved' && (a === null || !a)) return false;
      if(FF.status === 'missed'   && (a === null ||  a)) return false;
    }
    return true;
  });
}

/* Contextual empty state — no "No Data" */
function emptyState(ctx){
  const dn=(F&&F.dept&&F.dept!=='all'&&DM&&DM[F.dept])?(lang==='ar'?DM[F.dept].ar:DM[F.dept].en):'';
  const _fqtr=(F&&Array.isArray(F.qtr))?F.qtr:['q1'];const qStr=_fqtr.includes('all')?'':_fqtr.map(q=>q.toUpperCase()).join(' & ');
  const yStr=(F&&F.year&&F.year!=='all')?F.year:'';
  const period=[yStr,qStr].filter(Boolean).join(' ');
  const _FF=(typeof F!=='undefined'&&F&&typeof F==='object')?F:{year:'all',qtr:['q1','q2','q3','q4'],dept:'all',status:'all'};
  if(ctx==='missed'||_FF.status==='missed'){
    /* Check if really all Met */
    const filtKpis=filt();
    const evalKpis=filtKpis.filter(k=>k&&ok(k)!==null);
    const reallyAllMet=evalKpis.length>0&&evalKpis.every(k=>ok(k)===true);
    if(reallyAllMet||ctx==='missed'){
      const dept=dn?` for ${dn}`:'';
      const per=period?` in ${period}`:'';
      return lang==='ar'
        ?` جميع مؤشرات${dn?' '+dn:''} محققة${period?' خلال '+period:''}!<br>لا توجد مؤشرات Missed لعرضها — حُقِّق كل هدف.`
        :` All KPIs${dept} Are Met${per}!<br>No missed KPIs to display — every target has been achieved.`;
    }
  }
  if(ctx==='kpis'){
    const evalAll=allK().filter(k=>ok(k)!==null);
    const metAll=evalAll.length>0&&evalAll.every(k=>ok(k)===true);
    if(metAll&&_FF.status==='missed')
      return lang==='ar'?' جميع الأهداف محققة! لا توجد مؤشرات Missed.':' All Targets Achieved! No missed KPIs.';
    return lang==='ar'
      ?' لا توجد مؤشرات تطابق الفلتر المحدد.<br>جرب تغيير السنة أو الربع أو الحالة.'
      :' No KPIs match the selected filter.<br>Try adjusting the year, quarter, or status.';
  }
  return lang==='ar'?'لا توجد بيانات للفترة المحددة.':'No data for the selected period.';
}

