/* ==========================================================
   FINAL QUMC FIX — filter-aware forecast/current performance + latest reset
   ========================================================== */
(function(){
  function _num(v){ if(v===null||v===undefined||v==='') return null; var n=Number(v); return isFinite(n)?n:null; }
  function _avg(a){ var v=(a||[]).filter(function(x){return x!==null&&x!==undefined&&isFinite(x);}); return v.length?v.reduce(function(s,x){return s+x;},0)/v.length:null; }
  function _qtrs(){ return ['q1','q2','q3','q4']; }
  function _dept(k){ return String((k&&k.dept)||''); }
  function _nameKey(k){ return String((k&&(k.nameEn||k.nameAr||k.name||k.id))||'').trim().toLowerCase().replace(/\s+/g,' '); }
  function _hasActual(k){ return _qtrs().some(function(q){ return _num(k&&k[q])!==null; }); }
  function _filterBase(all, opts){
    opts=opts||{};
    var FF=(typeof F!=='undefined'&&F&&typeof F==='object')?F:{year:'all',qtr:['q1','q2','q3','q4'],dept:'all',status:'all'};
    var dept=opts.dept || (opts.respectFilters&&FF.dept&&FF.dept!=='all'?FF.dept:null) || (opts.respectFilters&&window._lockedDept?window._lockedDept:null);
    var year=opts.year || (opts.respectFilters&&FF.year&&FF.year!=='all'?FF.year:null);
    var status=opts.status || (opts.respectFilters&&FF.status&&FF.status!=='all'?FF.status:null);
    return (all||[]).filter(function(k){
      if(!k||typeof k!=='object') return false;
      if(dept&&_dept(k)!==String(dept)) return false;
      if(year&&String(k.yr)!==String(year)) return false;
      if(status&&typeof ok==='function'){
        var o=ok(k);
        if(status==='achieved'&&(o===null||o!==true)) return false;
        if(status==='missed'&&(o===null||o!==false)) return false;
      }
      return _hasActual(k);
    });
  }
  window.calcForecastYE=function(opts){
    opts=opts||{};
    var all=(typeof allK==='function')?allK():[];
    var filterForScope=!!opts.respectFilters || !!opts.dept || !!opts.year || !!opts.status;
    var base=filterForScope?_filterBase(all,opts):all.filter(_hasActual);
    if(!base.length) return {exec:null,byDept:{},currentYear:null,kpis:[]};
    var currentYear=base.reduce(function(m,k){var y=Number(k.yr)||0;return y>m?y:m;},0);
    if(!currentYear) return {exec:null,byDept:{},currentYear:null,kpis:[]};
    var groups={};
    base.forEach(function(k){
      var y=Number(k.yr)||0; if(!y||y>currentYear) return;
      var key=_nameKey(k)+'__'+_dept(k);
      if(!groups[key]) groups[key]={key:key,nameEn:k.nameEn||k.name||k.id||'',nameAr:k.nameAr||'',dept:_dept(k),hist:[],cur:[],curQs:{},codes:{}};
      if(k.id) groups[key].codes[String(k.id)]=true;
      _qtrs().forEach(function(q){
        var v=_num(k[q]); if(v===null) return;
        groups[key].hist.push(v);
        if(y===currentYear){ groups[key].cur.push(v); groups[key].curQs[q]=true; }
      });
    });
    var items=[], deptBuckets={};
    Object.keys(groups).forEach(function(key){
      var g=groups[key], h=_avg(g.hist), c=_avg(g.cur), entered=Object.keys(g.curQs||{}).length;
      if(h===null||c===null||entered<1) return;
      if(entered>4) entered=4;
      var forecast = entered>=4 ? c : ((1-(entered/4))*h)+((entered/4)*c);
      var item={key:g.key,nameEn:g.nameEn,nameAr:g.nameAr,dept:g.dept,currentYear:currentYear,enteredQuarters:entered,historicalAverage:h,currentYearAverage:c,forecast:forecast,codes:Object.keys(g.codes)};
      items.push(item);
      if(!deptBuckets[g.dept]) deptBuckets[g.dept]=[];
      deptBuckets[g.dept].push(forecast);
    });
    var byDept={}; Object.keys(deptBuckets).forEach(function(d){byDept[d]=_avg(deptBuckets[d]);});
    return {exec:_avg(items.map(function(x){return x.forecast;})),byDept:byDept,currentYear:currentYear,kpis:items};
  };
  window.calcCurrentPerformanceBreakdown=function(opts){
    opts=opts||{};
    var all=(typeof allK==='function')?allK():[];
    var FF=(typeof F!=='undefined'&&F&&typeof F==='object')?F:{year:'all',qtr:['q1','q2','q3','q4'],dept:'all',status:'all'};
    var ks=_filterBase(all,{respectFilters:true,dept:opts.dept||null,status:opts.status||null,year:opts.year||null});
    var qtrs=(Array.isArray(FF.qtr)&&!FF.qtr.includes('all'))?FF.qtr:_qtrs();
    function hasQ(k){return qtrs.some(function(q){return _num(k&&k[q])!==null;});}
    ks=ks.filter(hasQ);
    if((!FF.year||FF.year==='all')&&!opts.year){
      var ly=ks.reduce(function(m,k){var y=Number(k.yr)||0;return y>m?y:m;},0);
      if(ly) ks=ks.filter(function(k){return Number(k.yr)===ly;});
    }
    function qvLocal(k){var vals=qtrs.map(function(q){return _num(k[q]);}).filter(function(v){return v!==null;});return _avg(vals);}
    var vals=ks.map(qvLocal).filter(function(v){return v!==null;});
    var overall=_avg(vals);
    var byDept={};
    ['maintenance','safety','housekeeping','projects'].forEach(function(d){
      var dv=ks.filter(function(k){return _dept(k)===d;}).map(qvLocal).filter(function(v){return v!==null;});
      byDept[d]=_avg(dv);
    });
    return {exec:overall,byDept:byDept,kpis:ks};
  };
  window.getLatestPeriod=function(){
    try{
      if(typeof ST!=='undefined'&&ST&&ST._lastDataPeriod&&ST._lastDataPeriod.year&&ST._lastDataPeriod.qtr){
        return {year:String(ST._lastDataPeriod.year),qtrs:[String(ST._lastDataPeriod.qtr).toLowerCase()]};
      }
    }catch(_e){}
    var all=(typeof allK==='function'?allK():(typeof BASE!=='undefined'?BASE:[]));
    var best=null;
    _qtrs().forEach(function(q,idx){
      (all||[]).forEach(function(k){
        var v=_num(k&&k[q]); if(v===null) return;
        var y=Number(k.yr)||0; if(!y) return;
        var score=y*10+(idx+1);
        if(!best||score>best.score) best={year:y,qtr:q,score:score};
      });
    });
    if(best) return {year:String(best.year),qtrs:[best.qtr]};
    return {year:String(new Date().getFullYear()),qtrs:['q1']};
  };
  var _oldReset=window.resetFilters||resetFilters;
  window.resetFilters=resetFilters=function(){
    var lp=window.getLatestPeriod();
    F.year=lp.year; F.qtr=lp.qtrs; F.dept=window._lockedDept||'all'; F.status='all';
    document.querySelectorAll('[data-filter="year"]').forEach(function(b){b.classList.toggle('on',b.dataset.val===F.year);});
    document.querySelectorAll('[data-filter="qtr"]').forEach(function(b){b.classList.toggle('on',b.dataset.val==='all'?F.qtr.length===4:F.qtr.includes(b.dataset.val));});
    document.querySelectorAll('[data-filter="status"]').forEach(function(b){b.classList.toggle('on',b.dataset.val==='all');});
    document.querySelectorAll('[data-filter="dept"]').forEach(function(b){b.classList.toggle('on',b.dataset.val===F.dept);});
    var df=document.getElementById('deptF'); if(df) df.value=F.dept;
    if(typeof applyDepartmentFilterScope==='function')applyDepartmentFilterScope();
    if(typeof renderCurrent==='function') renderCurrent();
  };
})();

/* FINAL QUMC FIX — keep reset tied to latest real entered value */
(function(){
  function _num(v){ if(v===null||v===undefined||v==='') return null; var n=Number(v); return isFinite(n)?n:null; }
  function _syncLastDataPeriod(){
    try{
      var all=(typeof allK==='function')?allK():[]; var best=null;
      ['q1','q2','q3','q4'].forEach(function(q,idx){
        all.forEach(function(k){ var v=_num(k&&k[q]); if(v===null) return; var y=Number(k.yr)||0; if(!y) return; var score=y*10+(idx+1); if(!best||score>best.score) best={year:String(y),qtr:q,score:score}; });
      });
      if(best&&typeof ST!=='undefined'&&ST) ST._lastDataPeriod={year:best.year,qtr:best.qtr};
    }catch(e){console.warn('[latest period sync]',e);}
  }
  window._syncLastDataPeriod=_syncLastDataPeriod;
  var _oldPersist=window.persistST||persistST;
  if(typeof _oldPersist==='function'){
    window.persistST=window.persistSTWrapper=persistST=function(reason){ _syncLastDataPeriod(); return _oldPersist.apply(this,arguments); };
  }
})();


/* ==========================================================
   QUMC AR/KPI NORMALIZATION — Arabic mode only where applicable.
   - Department Arabic labels.
   - Arabic KPI names for maintenance/core KPIs.
   - Responsible person Arabic names by department.
   ========================================================== */
(function(){
  var KPI_AR={
    'Preventive Maintenance Compliance':'معدل الالتزام بالصيانة الوقائية',
    'Corrective Maintenance Resolution Rate':'معدل إغلاق طلبات الصيانة التصحيحية',
    'Fire Safety Compliance':'معدل الالتزام بالسلامة من الحريق',
    'Emergency Drill Compliance':'معدل الالتزام بتمارين الطوارئ',
    'Hazardous Waste Segregation Rate':'معدل الفصل الصحيح للنفايات الطبية الخطرة',
    'Emergency Request Response Time':'الالتزام بوقت الاستجابة للطلبات الطارئة',
    'Hygiene Standards Compliance':'معدل الالتزام بمعايير النظافة',
    'Laundry Turnaround Time Compliance':'الالتزام بوقت دورة الغسيل',
    'Schedule Performance Index':'مؤشر أداء الجدول الزمني'
  };
  var OWNER_AR={maintenance:'وليد الصريخ',projects:'سلمان الخضيري',housekeeping:'اسامه الغفيص',safety:'مشاري الصعب'};
  var OWNER_EN={maintenance:'Waleed Alsuraykh',projects:'Salman Alkhodairi',housekeeping:'Osamah Algafes',safety:'Meshari Alsaab'};
  window.qumcDeptOwner=function(dept){return (typeof lang!=='undefined'&&lang==='ar')?(OWNER_AR[dept]||'غير محدد'):(OWNER_EN[dept]||'Unassigned');};
  function normalizeOne(k){
    if(!k||typeof k!=='object')return k;
    if(k.nameEn&&KPI_AR[k.nameEn]&&(!k.nameAr||/^[\x00-\x7F\s\-()/%]+$/.test(String(k.nameAr)))) k.nameAr=KPI_AR[k.nameEn];
    if(k.dept==='maintenance'&&k.nameEn&&KPI_AR[k.nameEn]) k.nameAr=KPI_AR[k.nameEn];
    return k;
  }
  try{ if(window.DM&&DM.housekeeping)DM.housekeeping.ar='النظافة'; }catch(_){ }
  try{ if(Array.isArray(window.BASE))window.BASE.forEach(normalizeOne); }catch(_){ }
  var oldAll=window.allK;
  if(typeof oldAll==='function'){
    window.allK=function(){ var arr=oldAll.apply(this,arguments)||[]; try{arr.forEach(normalizeOne);}catch(_){ } return arr; };
    try{ allK=window.allK; }catch(_){ }
  }
})();


/* QUMC Forecast YE correction — 2026-06-25
   Fixes: Forecast should not collapse to Current Performance just because Year filter is selected.
   Forecast respects department/status scope, but Historical Average includes prior years up to selected/current year.
*/
(function(){
  function parseNum(v){
    if(v===null||v===undefined||v==='')return null;
    var s=String(v).trim();
    if(!s||s==='—'||s==='-')return null;
    s=s.replace(/[٪%]/g,'').replace(/,/g,'').replace(/\s+/g,'');
    s=s.replace(/[٠-٩]/g,function(c){return '٠١٢٣٤٥٦٧٨٩'.indexOf(c);});
    s=s.replace(/[۰-۹]/g,function(c){return '۰۱۲۳۴۵۶۷۸۹'.indexOf(c);});
    var n=Number(s);return isFinite(n)?n:null;
  }
  function avg(a){var v=(a||[]).filter(function(x){return x!==null&&x!==undefined&&isFinite(x);});return v.length?v.reduce(function(s,x){return s+x;},0)/v.length:null;}
  function deptOf(k){return String((k&&k.dept)||'');}
  function qtrs(){return ['q1','q2','q3','q4'];}
  function qVal(k,q){var v=k&&k[q]; if(v===undefined)v=k&&k[q.toUpperCase()]; return parseNum(v);}
  function hasAny(k){return qtrs().some(function(q){return qVal(k,q)!==null;});}
  function kKey(k){return String((k&&(k.id||k.code||k.kpiCode))||((k&&(k.nameEn||k.nameAr||k.name||k.title))||'')).trim().toLowerCase().replace(/\s+/g,'_')+'__'+deptOf(k);}
  function statusOk(k,status){
    if(!status||status==='all')return true;
    if(typeof ok==='function'){
      var o=ok(k);
      if(status==='achieved')return o===true;
      if(status==='missed')return o===false;
    }
    return true;
  }
  window.calcForecastYE=function(opts){
    opts=opts||{};
    var all=(typeof allK==='function'?allK():[]).filter(function(k){return k&&typeof k==='object'&&hasAny(k);});
    var FF=(typeof F!=='undefined'&&F&&typeof F==='object')?F:{};
    var dept=opts.dept || (opts.respectFilters&&FF.dept&&FF.dept!=='all'?FF.dept:null) || (opts.respectFilters&&window._lockedDept?window._lockedDept:null);
    var status=opts.status || (opts.respectFilters&&FF.status&&FF.status!=='all'?FF.status:null);
    all=all.filter(function(k){return (!dept||deptOf(k)===String(dept)) && statusOk(k,status);});
    if(!all.length)return {exec:null,byDept:{},currentYear:null,kpis:[]};
    var selectedYear=opts.year || (opts.respectFilters&&FF.year&&FF.year!=='all'?Number(FF.year):null);
    if(!selectedYear){selectedYear=all.reduce(function(m,k){var y=Number(k.yr)||0;return y>m?y:m;},0);}
    if(!selectedYear)return {exec:null,byDept:{},currentYear:null,kpis:[]};
    var selectedQs=null;
    /* Forecast YE is a year-end estimate, so it uses all actual quarters entered
       in the selected/current year. Quarter filter affects Current Performance,
       not the Forecast YE calculation, to avoid Q1-only forecast collapsing into
       the same value as Current Performance. */
    var groups={};
    all.forEach(function(k){
      var y=Number(k.yr)||0; if(!y||y>selectedYear)return;
      var key=kKey(k);
      if(!groups[key])groups[key]={key:key,nameEn:k.nameEn||k.name||k.id||'',nameAr:k.nameAr||'',dept:deptOf(k),hist:[],cur:[],curQs:{},codes:{}};
      if(k.id)groups[key].codes[String(k.id)]=true;
      qtrs().forEach(function(q){
        var v=qVal(k,q); if(v===null)return;
        if(y<selectedYear){groups[key].hist.push(v);return;}
        if(y===selectedYear){
          if(selectedQs && selectedQs.indexOf(q)<0)return;
          groups[key].hist.push(v);groups[key].cur.push(v);groups[key].curQs[q]=true;
        }
      });
    });
    var items=[],buckets={};
    Object.keys(groups).forEach(function(key){
      var g=groups[key],h=avg(g.hist),c=avg(g.cur),entered=Object.keys(g.curQs).length;
      if(h===null||c===null||entered<1)return;
      if(entered>4)entered=4;
      var forecast=entered>=4?c:((1-(entered/4))*h)+((entered/4)*c);
      var item={key:g.key,nameEn:g.nameEn,nameAr:g.nameAr,dept:g.dept,currentYear:selectedYear,enteredQuarters:entered,historicalAverage:h,currentYearAverage:c,forecast:forecast,codes:Object.keys(g.codes)};
      items.push(item); if(!buckets[g.dept])buckets[g.dept]=[]; buckets[g.dept].push(forecast);
    });
    var byDept={};Object.keys(buckets).forEach(function(d){byDept[d]=avg(buckets[d]);});
    return {exec:avg(items.map(function(x){return x.forecast;})),byDept:byDept,currentYear:selectedYear,kpis:items};
  };
})();

/* ==========================================================
   QUMC FINAL FORECAST FIX — name+department historical grouping
   - Current year can come from selected Year filter, but history is NOT limited to that year.
   - Per-KPI forecast groups same KPI name within same department across different codes/years.
   - Quarter filter does not limit Forecast YE; it remains a year-end estimate.
   ========================================================== */
(function(){
  function _fNum(v){
    if(v===null||v===undefined||v==='') return null;
    var s=String(v).trim();
    if(!s||s==='—'||s==='-'||/^n\/?a$/i.test(s)) return null;
    s=s.replace(/[٪%]/g,'').replace(/,/g,'').replace(/\s+/g,'');
    s=s.replace(/[٠-٩]/g,function(c){return '٠١٢٣٤٥٦٧٨٩'.indexOf(c);});
    s=s.replace(/[۰-۹]/g,function(c){return '۰۱۲۳۴۵۶۷۸۹'.indexOf(c);});
    var n=Number(s);
    return isFinite(n)?n:null;
  }
  function _fAvg(arr){var v=(arr||[]).filter(function(x){return x!==null&&x!==undefined&&isFinite(x);});return v.length?v.reduce(function(a,b){return a+b;},0)/v.length:null;}
  function _fDept(k){return String((k&&k.dept)||'').trim();}
  function _fQtrs(){return ['q1','q2','q3','q4'];}
  function _fQVal(k,q){
    if(!k) return null;
    var v=k[q];
    if(v===undefined) v=k[q.toUpperCase()];
    if((v===undefined||v===null||v==='') && k._custom && k._result!==undefined) v=k._result;
    return _fNum(v);
  }
  function _fHasAny(k){return _fQtrs().some(function(q){return _fQVal(k,q)!==null;});}
  function _fName(k){return String((k&&(k.nameEn||k.name||k.title||k.nameAr||k.id||k.code||k.kpiCode))||'').trim();}
  function _fNormName(s){
    return String(s||'').toLowerCase().trim()
      .replace(/[\u200e\u200f]/g,'')
      .replace(/\b(rate|compliance|kpi|indicator)\b/g,function(m){return m;})
      .replace(/[^a-z0-9\u0600-\u06ff]+/g,' ')
      .replace(/\s+/g,' ')
      .trim();
  }
  function _fGroupKey(k){
    var nm=_fNormName(_fName(k));
    if(!nm) nm=String((k&&(k.id||k.code||k.kpiCode))||'').toLowerCase();
    return nm+'__'+_fDept(k);
  }
  function _fCode(k){return String((k&&(k.id||k.code||k.kpiCode))||'').trim();}
  function _fYear(k){return Number(k&&(k.yr||k.year||k.fy))||0;}
  function _fStatusOk(k,status){
    if(!status||status==='all') return true;
    try{
      if(typeof ok==='function'){
        var o=ok(k);
        if(status==='achieved') return o===true;
        if(status==='missed') return o===false;
      }
    }catch(_){ }
    return true;
  }
  function _fScope(all,opts){
    opts=opts||{};
    var FF=(typeof F!=='undefined'&&F&&typeof F==='object')?F:{};
    var dept=opts.dept || (opts.respectFilters&&FF.dept&&FF.dept!=='all'?FF.dept:null) || (opts.respectFilters&&window._lockedDept?window._lockedDept:null);
    var status=opts.status || (opts.respectFilters&&FF.status&&FF.status!=='all'?FF.status:null);
    return (all||[]).filter(function(k){
      if(!k||typeof k!=='object'||!_fHasAny(k)) return false;
      if(dept && _fDept(k)!==String(dept)) return false;
      if(status && !_fStatusOk(k,status)) return false;
      return true;
    });
  }
  window.calcForecastYE=function(opts){
    opts=opts||{};
    var FF=(typeof F!=='undefined'&&F&&typeof F==='object')?F:{};
    var all=(typeof allK==='function'?allK():[]);
    var base=_fScope(all,opts);
    if(!base.length) return {exec:null,byDept:{},currentYear:null,kpis:[]};
    var selectedYear=opts.year || (opts.respectFilters&&FF.year&&FF.year!=='all'?Number(FF.year):null);
    if(!selectedYear) selectedYear=base.reduce(function(m,k){var y=_fYear(k);return y>m?y:m;},0);
    if(!selectedYear) return {exec:null,byDept:{},currentYear:null,kpis:[]};

    var groups={};
    base.forEach(function(k){
      var y=_fYear(k);
      if(!y || y>selectedYear) return;
      var key=_fGroupKey(k);
      if(!groups[key]) groups[key]={key:key,nameEn:(k.nameEn||k.name||k.id||''),nameAr:(k.nameAr||''),dept:_fDept(k),hist:[],cur:[],curQs:{},codes:{}};
      var c=_fCode(k); if(c) groups[key].codes[c]=true;
      _fQtrs().forEach(function(q){
        var v=_fQVal(k,q);
        if(v===null) return;
        groups[key].hist.push(v);
        if(y===selectedYear){groups[key].cur.push(v);groups[key].curQs[q]=true;}
      });
    });
    var items=[],deptBuckets={};
    Object.keys(groups).forEach(function(key){
      var g=groups[key];
      var h=_fAvg(g.hist), c=_fAvg(g.cur), entered=Object.keys(g.curQs||{}).length;
      if(h===null||c===null||entered<1) return;
      if(entered>4) entered=4;
      var hw=(4-entered)/4, cw=entered/4;
      var forecast=(entered>=4)?c:(hw*h)+(cw*c);
      var item={key:g.key,nameEn:g.nameEn,nameAr:g.nameAr,dept:g.dept,currentYear:selectedYear,enteredQuarters:entered,historicalAverage:h,currentYearAverage:c,forecast:forecast,codes:Object.keys(g.codes)};
      items.push(item);
      if(!deptBuckets[g.dept]) deptBuckets[g.dept]=[];
      deptBuckets[g.dept].push(forecast);
    });
    var byDept={};Object.keys(deptBuckets).forEach(function(d){byDept[d]=_fAvg(deptBuckets[d]);});
    return {exec:_fAvg(items.map(function(x){return x.forecast;})),byDept:byDept,currentYear:selectedYear,kpis:items};
  };
})();
